"""
mkt-original layer — Revelation chapters 12–16 (all verses)
Output: data/commentary/mkt-original/revelation.json
Run: python3 scripts/zc-original-revelation-12-16-full.py

Key term decisions:
- θηρίον (ch13): 'beast/wild animal' — the term for a savage, dangerous animal vs. ζῷον
  (living creature, used of the four heavenly beings); the deliberate contrast is maintained
- χάραγμα (ch13v16-17): 'mark/brand' — a stamped or engraved mark, used for brands on
  animals or slave-marks; the antithesis of the seal of God (ch7v2-3)
- δρέπανον (ch14): 'sickle' — the harvest implement; Joel 3:13 LXX prototype is decisive
- φιάλη (ch16): 'bowl/basin' — a wide flat bowl used for libations; the anti-eucharist
  of poured wrath vs. poured sacrifice
- ἀπαρχή (ch14v4): 'firstfruits' — the term from the Hebrew qorban offering typology
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {
  "12": {
    "1": "<p><em>Sēmeion mega</em> (a great sign) — introduces a symbolic vision, distinguishing it from a literal scene; the same term governs 12:3 and 15:1. The woman (<em>gynē</em>) clothed with the sun (<em>peribeblēmenē ton hēlion</em>), moon under feet, twelve-star crown (<em>stephanos asterōn dōdeka</em>) is a corporate figure: in Joseph's dream (Gen 37:9) sun, moon, and eleven stars bow to Joseph, making the woman Israel-as-mother-of-the-Messiah rather than an individual. The crown (<em>stephanos</em>) is the victor's wreath, not a royal diadem (<em>diadēma</em>), marking her dignity within the divine order.</p>",
    "2": "<p><em>En gastri echousa</em> (having [a child] in the womb) — the pregnancy motif evokes Isa 66:7-8 (before she was in labor she gave birth, before her pain came she delivered a son). The cry and labor (<em>krazei ōdinousa kai basanizomenē tektein</em>) recalls Isa 26:17-18 and Mic 5:3 (she who is in labor brings forth). The Greek <em>basanizomenē</em> (tormented/pained) emphasizes the agony of the messianic birth process — the travail that produces the Son is the whole history of Israel under pressure.</p>",
    "3": "<p><em>Drakōn megas pyrros</em> (a great fiery/red dragon) — the second <em>sēmeion</em>. The dragon is explicitly identified as the ancient serpent/Satan in v9; here the attributes (<em>hepta kephalai</em> seven heads, <em>deka kerata</em> ten horns, <em>hepta diadēmata</em> seven diadems) map to the beast of ch13 and the whore of ch17, establishing that the dragon is the source-power behind all anti-God imperial structures. Note <em>diadēmata</em> (royal crowns, the word for rulers' crowns) on the dragon, contrasting with the woman's <em>stephanos</em> (victors' wreath).</p>",
    "4": "<p><em>Hē ourā autou syrei to triton tōn asterōn</em> (his tail sweeps a third of the stars) — the <em>ourā</em> (tail) sweeping stars alludes to Dan 8:10 (the little horn grew great and threw down some of the host of the stars to the ground). The dragon's station before the woman about to give birth (<em>hestēken enōpion tēs gynaikos... hina hotan tektē to teknon autēs kataphagē</em>) establishes the cosmic conflict at the moment of the messianic birth; the devouring attempt is the prototype of Herod's massacre (Matt 2:16) and all subsequent persecution of the Messiah's people.</p>",
    "5": "<p><em>Etekon huion arren</em> (she gave birth to a son, a male child) — the redundancy (son + male) echoes the LXX of Isa 66:7 (<em>eteken arsen</em>). <em>Poimainein panta ta ethnē en rhabdō sidērā</em> (to rule all the nations with an iron rod) cites Ps 2:9 LXX, the definitive messianic enthronement psalm. The immediately following <em>hērpasthē to teknon autēs pros ton theon</em> (her child was snatched up to God) compresses the entire earthly life, death, and ascension of Jesus into a single image — the birth leads directly to enthronement, with the cross implied but not described; the pattern is the exaltation schema of Phil 2:9-11.</p>",
    "6": "<p><em>Ephygen hē gynē eis tēn erēmon</em> (the woman fled into the wilderness) — the wilderness (<em>erēmos</em>) is the place of divine provision and protection, the exodus typology: God's provision for Israel in the wilderness (Exod 16-17; Num 11) is the structural pattern. The <em>chilia diakosiai hexēkonta hēmerai</em> (1,260 days = 42 months = 3.5 years) is the apocalyptic time-unit from Dan 7:25 and 12:7 (time, times, and half a time), establishing that the period of the woman's protection is the period of the beast's authority — the same 42 months as 13:5.</p>",
    "7": "<p><em>Egeneto polemos en tō ouranō</em> (war broke out in heaven) — the heavenly war is the cosmic consequence of the child's enthronement (v5). <em>Ho Michaēl kai hoi angeloi autou</em> (Michael and his angels) — Michael is the angelic patron of Israel in Dan 10:13, 21; 12:1 (the great prince who protects your people). The war in heaven is the inauguration of the eschatological conflict that has already been decided by the cross (cf. John 12:31: now the ruler of this world will be cast out).</p>",
    "8": "<p><em>Ouk ischysen</em> (he was not strong enough) — the aorist passive indicates completed action: the dragon's defeat is decisive and past; the description of the earthly warfare (vv. 13-17) is the working-out of a defeat already accomplished in heaven. <em>Oute topos heurethē autōn eti en tō ouranō</em> (no longer any place for them in heaven) — the language of <em>topos</em> (place) being denied them echoes Job 1-2 where Satan has access to the heavenly court; this access is now permanently revoked.</p>",
    "9": "<p><em>Ho drakōn ho megas, ho ophis ho archaios</em> (the great dragon, the ancient serpent) — the explicit identification links the dragon with the serpent of Gen 3, establishing the entire narrative from Genesis as the backstory of the dragon's cosmic conflict with the woman's offspring (Gen 3:15: I will put enmity between you and the woman). The fourfold name — dragon, ancient serpent, devil (<em>diabolos</em>), Satan (<em>Satanas</em>) — is a cumulative identification that exhausts the enemy's titles. <em>Ho planōn tēn oikoumenēn holēn</em> (the one deceiving the whole inhabited world) — <em>planaō</em> (deceive/lead astray) is his primary mode of operation, key for ch13's false-prophet deception.</p>",
    "10": "<p><em>Arti egeneto hē sōtēria kai hē dynamis kai hē basileia tou theou</em> (now have come the salvation and the power and the kingdom of God) — the heavenly proclamation of three nouns: <em>sōtēria</em> (salvation/rescue), <em>dynamis</em> (power), <em>basileia</em> (kingdom/reign). The <em>arti</em> (now/just now) is the eschatological moment — the casting-out of the accuser marks the arrival of God's reign. <em>Ho katēgōr tōn adelphōn hēmōn</em> (the accuser of our brothers) — <em>katēgōr</em> is the legal-forensic term for the prosecutor; the dragon's role as cosmic prosecuting attorney (Job 1-2; Zech 3:1) is now terminated by Christ's atoning work.</p>",
    "11": "<p><em>Autoi enikēsan auton dia to haima tou arniou</em> (they conquered him by the blood of the Lamb) — the triple victory formula: (1) <em>haima tou arniou</em> (blood of the Lamb) — the atoning work of Christ; (2) <em>ho logos tēs martyrias autōn</em> (the word of their testimony) — the proclamatory witness; (3) <em>ouk ēgapēsan tēn psychēn autōn achri thanatou</em> (they did not love their life unto death) — the willingness to die. The verb <em>nikaō</em> (conquer/overcome) is the key term of the seven letters (ch2-3); here its ground is revealed: conquest comes through Christ's blood appropriated by faithful witness.</p>",
    "12": "<p><em>Dia touto euphrainesthē, hoi ouranoi</em> (therefore rejoice, O heavens) — the heavenly rejoicing for the dragon's expulsion; the imperative <em>euphrainesthē</em> addresses the heavens personified. <em>Ouai tē gē kai tē thalassē</em> (woe to the earth and the sea) — the dragon's descent brings <em>thymon megan</em> (great wrath/fury); <em>eidōs hoti oligon kairon echei</em> (knowing that his time is short) — the dragon's fury is proportional to his eschatological desperation; the <em>kairos</em> is his appointed time, which is brief and counted.</p>",
    "13": "<p><em>Edīōxen tēn gynaika</em> (he pursued the woman) — the dragon's post-expulsion campaign against the woman and her remaining offspring. The earthly persecution is the grounded expression of the heavenly war; the woman's flight to the wilderness (v6) is revisited with the eagle-wings imagery.</p>",
    "14": "<p><em>Edothēsan tē gynaiki hai dyo pteryges tou aetou</em> (the woman was given two wings of a great eagle) — the passive <em>edothēsan</em> (were given) signals divine provision; the eagle-wings echo Exod 19:4 (I bore you on eagles' wings and brought you to myself) — the exodus deliverance typology applied to the end-time community. The <em>kairos kai kairoi kai hēmisy kairou</em> (time and times and half a time) recites Dan 12:7 LXX exactly, reinforcing the three-and-a-half year apocalyptic period.</p>",
    "15": "<p><em>Ebalen ho ophis ek tou stomatos autou opisō tēs gynaikos hydōr hōs potamon</em> (the serpent poured water from his mouth like a river after the woman) — the flood-as-weapon employs the OT imagery of overwhelming enemies as flood-waters (Ps 32:6; Isa 59:19; Dan 11:22). The water from the serpent's mouth contrasts with the sword from Christ's mouth (1:16; 2:12); the dragon speaks destruction, Christ speaks the word that conquers.</p>",
    "16": "<p><em>Ēnoixen hē gē to stoma autēs kai katepien ton potamon</em> (the earth opened its mouth and swallowed the river) — the earth swallowing alludes to Num 16:32 (the ground opened and swallowed Korah and his companions) and Exod 15:12 (you stretched out your right hand and the earth swallowed them). The earth rescuing the woman is a reversal of the usual earth-as-hostile image; creation itself serves the woman's protection.</p>",
    "17": "<p><em>Kai ōrgisthē ho drakōn epi tē gynaiki kai apēlthen poiēsai polemon meta tōn loipōn tou spermatos autēs</em> (the dragon was furious and went off to make war against the rest of her offspring) — <em>loipōn tou spermatos</em> (the rest of her seed) echoes Gen 3:15's enmity with the woman's seed. The identifying marks of her offspring: <em>tōn tērountōn tas entolas tou theou kai echontōn tēn martyrian Iēsou</em> (those keeping God's commands and having the testimony of Jesus) — the combination of Torah-fidelity and Jesus-witness defines the true messianic community.</p>"
  },
  "13": {
    "1": "<p><em>Eidon ek tēs thalassēs thērion anabainon</em> (I saw a beast rising out of the sea) — the sea (<em>thalassa</em>) in Jewish apocalyptic represents the chaos-realm from which hostile powers emerge (Dan 7:3). The beast's attributes (<em>deka kerata kai hepta kephalai</em>, ten horns and seven heads) invert the Lamb's seven horns and seven eyes (5:6); this is the anti-Lamb. The dragon gives it his own attributes (cf. 12:3), making it the dragon's embodied agent in history. The horns bear diadems (<em>diadēmata</em>, royal crowns) rather than victor's wreaths, signaling political-imperial authority.</p>",
    "2": "<p><em>Pardomardē homoion leopardō... arktos... leōn</em> (like a leopard... bear... lion) — John reverses the sequence of Dan 7:4-6 (lion, bear, leopard), combining all four Danielic empires into one composite beast: the eschatological empire that absorbs all preceding imperial power. The dragon's gift of <em>dynamin kai thronon kai exousian megalēn</em> (power, throne, and great authority) makes explicit that all political authority exercised against God's people flows from the dragon; Paul's 'governing authorities' language of Rom 13 presupposes legitimate authority, while John's beast-vision diagnoses its demonic counterfeit.</p>",
    "3": "<p><em>Mian ek tōn kephalōn autou hōs esphagmenēn eis thanaton</em> (one of its heads as though slaughtered to death) — <em>esphagmenēn</em> is the same verb as the Lamb 'slaughtered' (<em>arnion... hōs esphagmenon</em>, 5:6); the beast performs a death-and-resurrection parody of the Lamb's death and resurrection, producing the same universal astonishment (<em>ethaumasthē holē hē gē opisō tou thēriou</em>, the whole earth marveled). The Nero redivivus tradition (the wounded head returning) is the historical referent, but John's point is structural: the beast imitates the Lamb's pattern to deceive.</p>",
    "4": "<p><em>Kai prosekunēsan tō drakoni... kai prosekunēsan tō thēriō</em> (they worshipped the dragon... and they worshipped the beast) — the double <em>proskyneō</em> (worship/bow down) is the idolatry act that marks the beast-allegiance community in contrast to those who worship the Lamb (14:1-3). <em>Tis homoios tō thēriō, kai tis dynatai polemēsai met autou</em> (who is like the beast, and who can make war against it?) — a parody of Exod 15:11 (who is like you, O LORD... majestic in holiness?) and Mic 7:18 (who is a God like you?); the imperial question of invincibility is the beast's worship formula.</p>",
    "5": "<p><em>Edothē autō stoma laloun megala kai blasphēmias</em> (it was given a mouth speaking great things and blasphemies) — the passive <em>edothē</em> (was given) appears seven times in ch13, signaling that even the beast's power operates within divinely permitted limits; its authority is derivative and bounded. The source is Dan 7:8, 11 (the little horn speaking great things). <em>Exousia poiēsai mēnas tesserakonta dyo</em> (authority to act for 42 months) = the same 3.5-year period of ch12:6 — the dragon and beast operate in the same divinely-limited timeframe.</p>",
    "6": "<p><em>Ēnoixen to stoma autou eis blasphēmias pros ton theon blasphēmēsai to onoma autou kai tēn skēnēn autou</em> (it opened its mouth in blasphemies against God, blaspheming his name and his dwelling) — the double <em>blasphēmia/blasphēmēsai</em> underscores the totalizing blasphemy: both the Name (<em>onoma</em>) that represents God's person and the <em>skēnē</em> (tabernacle/dwelling) — i.e., those who dwell in heaven — are targets. The blasphemy is anti-worship: where the elders and living creatures speak the name in doxology (4:8-11), the beast speaks the name in slander.</p>",
    "7": "<p><em>Edothē autō poiēsai polemon meta tōn hagiōn kai nikēsai autous</em> (it was given authority to make war on the saints and to conquer them) — the beast's warfare against the saints (<em>hagioi</em>) is the earthly expression of the dragon's war against the woman's offspring (12:17). Note: the beast is said to <em>nikēsai</em> (conquer/overcome) the saints — the same word the saints use for their own victory (12:11; 15:2; 21:7). From one angle the beast conquers; from another (ch15:2) the saints conquer the beast. The perspective determines the verdict.</p>",
    "8": "<p><em>Pantes hoi katoikountes epi tēs gēs proskynēsousin autō, hou ou gegraptai to onoma autou en tō bibliō tēs zōēs tou arniou tou esphagmenou apo katabolēs kosmou</em> — the book of life (<em>biblion tēs zōēs</em>) of the Lamb slaughtered from the foundation of the world. The phrase <em>apo katabolēs kosmou</em> (from the foundation of the world) modifies either the writing of names (names written before creation) or the slaughter of the Lamb (the Lamb's sacrifice as eternally decreed); the grammar favors the latter — the cross is an event in time but an act purposed before creation.</p>",
    "9": "<p><em>Ei tis echei ous akousatō</em> (if anyone has an ear, let him hear) — the identical formula from the seven letters (2:7, 11, 17, 29; 3:6, 13, 22), where it introduced the Spirit's promise to the overcomer. Here placed after the beast's worldwide authority, it calls for discernment: the appearance of the beast's triumph (v7-8) requires spiritual hearing to understand.</p>",
    "10": "<p><em>Ei tis eis aichmalōsian, eis aichmalōsian hypagei</em> (if anyone is to go into captivity, into captivity he will go) — Jer 15:2 LXX prototype (<em>ei eis thanaton, eis thanaton</em>). The verse reapplies the covenantal doom-formula from Jeremiah to the situation of persecution: the pattern is fixed; those destined for captivity will be captured. <em>Hōde estin hē hypomonē kai hē pistis tōn hagiōn</em> (here is the patient endurance and the faith of the saints) — the twin virtues required in the face of the fixed doom: <em>hypomonē</em> (patient endurance, steadfast perseverance) and <em>pistis</em> (faith/faithfulness).</p>",
    "11": "<p><em>Eidon allo thērion anabainon ek tēs gēs</em> (I saw another beast rising from the earth) — the land-beast, later identified as 'the false prophet' (16:13; 19:20; 20:10). Its attributes: <em>kerata dyo homoia arniō</em> (two horns like a lamb) — parody of the Lamb's seven horns; <em>elalei hōs drakōn</em> (it spoke like a dragon) — the wolf-in-sheep's-clothing image; the appearance of innocence (lamb) with the speech of destruction (dragon). This is the deceiver whose function is propaganda and religious manipulation in service of the first beast.</p>",
    "12": "<p><em>Kai tēn exousian tou prōtou thēriou pasan poiei enōpion autou</em> (it exercises all the authority of the first beast in its presence) — the false prophet is the political-religious enforcer of the first beast's cult. <em>Poiei tēn gēn kai tous en autē katoikountas hina proskunēsousin to thērion to prōton</em> (makes the earth and its inhabitants worship the first beast) — the religious function of the false prophet is compulsory worship-production; the three-fold parody of the Trinity is complete: dragon (father-parody), beast (son-parody), false prophet (spirit-parody).</p>",
    "13": "<p><em>Poiei sēmeia megala, hina kai pyr poiē ek tou ouranou katabainein</em> (it performs great signs, even making fire come down from heaven) — the fire from heaven parodies Elijah's fire from heaven (1 Kgs 18:38; 2 Kgs 1:10-12) and possibly Pentecost (Acts 2:3). The <em>sēmeia megala</em> (great signs) echo the Mosaic signs-and-wonders typology; Deut 13:1-3 warned that a prophet performing signs who calls for following other gods is a false prophet — the canonical criterion for false prophecy is applied here.</p>",
    "14": "<p><em>Planā tous katoikountas epi tēs gēs dia ta sēmeia</em> (it deceives those who dwell on earth by the signs) — <em>planaō</em> (deceive/lead astray) is the dragon's characteristic verb (12:9); the false prophet carries on the dragon's deceptive work through sign-performance. The <em>poiēsai eikona tō thēriō</em> (to make an image for the beast) establishes the idolatry requirement — the beast demands an <em>eikōn</em> (image/likeness), the same word used for God's image in humanity (Gen 1:26 LXX: <em>kat eikona hēmeteran</em>); the image-of-the-beast is the anti-creation of the divine image.</p>",
    "15": "<p><em>Dounai pneuma tē eikoni tou thēriou</em> (to give breath/spirit to the image of the beast) — the false prophet gives <em>pneuma</em> (breath/spirit) to the image; the word is the same as God's giving the breath of life (<em>pnoēn zōēs</em>) to Adam (Gen 2:7). The animated image that speaks and kills parodies the giving of the Spirit; the false prophet performs a demonic Pentecost — giving counterfeit spirit-life to produce compulsory worship and lethal enforcement.</p>",
    "16": "<p><em>Poiei pantas... hina dōsin autois charagma epi tēs cheiros autōn tēs dexias ē epi to metōpon autōn</em> (causes all... to be given a mark on their right hand or forehead) — the <em>charagma</em> (mark/brand) is the commercial-economic slavery brand, the antithesis of the seal of God on the servants' foreheads (7:3; cf. Ezek 9:4). The marking of forehead and hand inverts the Torah's phylactery instruction (Deut 6:8: bind them as a sign on your hand; they shall be as frontlets between your eyes).</p>",
    "17": "<p><em>Hina mē tis dynētai agorasai ē pōlēsai ei mē ho echōn to charagma</em> (so that no one could buy or sell unless he had the mark) — the economic exclusion of those without the mark is the practical enforcement mechanism: <em>agorasai/pōlēsai</em> (buy/sell) ties the mark to marketplace participation. The word <em>charagma</em> was also used for imperial coins bearing the emperor's image and name — the mark may reference the necessity of using Roman coinage (itself bearing the emperor's image) for all commercial activity.</p>",
    "18": "<p><em>Hōde hē sophia estin</em> (here is wisdom) — the call for wisdom (<em>sophia</em>) to calculate the beast's number; the same formula as 17:9 (here is the mind with wisdom). <em>Arithmos gar anthrōpou estin</em> (for it is the number of a human being) — the beast's number is human-scale: 666 is the triangular number of 36 (sum of 1-36), which is the triangular number of 6 (sum of 1-6); in gematria this most likely = Neron Kaisar in Hebrew script. The triple 6 falls short of the divine 7 — the beast's number is the number of human imperial pretension to deity, always falling one short of completion.</p>"
  },
  "14": {
    "1": "<p><em>To Arnion hestōs epi to oros Siōn</em> (the Lamb standing on Mount Zion) — the contrast with ch13: the beast rises from the sea amid the whole earth's worship, while the Lamb stands on Zion with the sealed 144,000 who bear his name and the Father's name on their foreheads (<em>to onoma autou kai to onoma tou patros autou gegrammenon</em>). The <em>hestōs</em> (standing) recalls 5:6 (a Lamb standing, as though slaughtered) — the risen Lamb's permanent posture of victorious presence. Mount Zion is the eschatological destination of Isa 24:23; Mic 4:1-7; Ps 48.</p>",
    "2": "<p><em>Phōnēn ek tou ouranou hōs phōnēn hydatōn pollōn kai hōs phōnēn brontēs megalēs</em> (a voice like the sound of many waters and like the sound of loud thunder) — the theophanic sound-description (cf. 1:15; 19:6) applied to the heavenly choir. The third simile: <em>hōs kitharodōn kitharizontōn en tais kitharais autōn</em> (like the sound of harpers harping on their harps) — the combination of awe-inspiring natural sound and precise musical instrument signals that the heavenly worship is simultaneously overwhelming and ordered.</p>",
    "3": "<p><em>ōdousin hōs ōdēn kainēn enōpion tou thronou</em> (they were singing something like a new song before the throne) — the <em>ōdē kainē</em> (new song) is the eschatological song of Ps 96:1; 98:1; Isa 42:10; Rev 5:9 (the Lamb's song). <em>Oudeis edynato mathein tēn ōdēn</em> (no one could learn the song) except the 144,000 — the song of the redeemed is not learnable by those outside that redemption; experiential knowledge of redemption is the prerequisite for participating in the new creation's worship.</p>",
    "4": "<p><em>Houtoi eisin hoi meta gynaikōn ouk emolyanthēsan, parthenoi gar eisin</em> (these are those who have not defiled themselves with women, for they are virgins) — <em>parthenoi</em> is almost certainly a metaphorical term for those who have not committed <em>porneia</em> in its spiritual sense (idolatry, beast-worship); the OT consistently uses sexual unfaithfulness as a metaphor for idolatry (Hos 1-3; Jer 3; Ezek 16). <em>Houtoi hoi akolouthountes tō arniō hopou hypagei</em> (they follow the Lamb wherever he goes) — the disciple's posture: they follow the Lamb's path, including his death-path. <em>Aparachē tō theō kai tō arniō</em> (firstfruits for God and the Lamb) — <em>aparchē</em> is the temple offering of the first of the harvest, dedicated to God; the 144,000 are consecrated to God and the Lamb as the first portion of the full harvest of ch14:14-20.</p>",
    "5": "<p><em>En tō stomati autōn ouch heurethē pseudos</em> (in their mouth no lie was found) — the contrast with the false prophet who deceives (<em>planaō</em>) through lies; the 144,000 are the anti-false-prophet community. <em>Amōmoi eisin</em> (they are blameless/without blemish) — the cultic term from Lev 1:3, 10 (the unblemished sacrificial animal); the 144,000 are themselves the sacrifice presented blameless to God, the human counterpart of the Lamb slaughtered without blemish (1 Pet 1:19: <em>amōmou kai aspilou</em>).</p>",
    "6": "<p><em>Euangelion aiōnion</em> (an eternal gospel) — the only occurrence of <em>euangelion</em> (gospel) in Revelation; the <em>aiōnion</em> (eternal/age-long) modifies it as the gospel that belongs to the eternal age, not a transient message. <em>Euangelisai tous kathēmenous epi tēs gēs kai epi pan ethnos kai phylēn kai glōssan kai laon</em> (to proclaim to those who dwell on earth and to every nation and tribe and language and people) — the universal mission formula reverses the beast's universal domain (13:7: authority over every tribe, people, language, and nation); the gospel claims the same universal scope.</p>",
    "7": "<p><em>Phobēthēte ton theon kai dote autō doxan, hoti ēlthen hē hōra tēs kriseōs autou</em> (fear God and give him glory, for the hour of his judgment has come) — the three imperatives of the first angel's message: fear (<em>phobēthēte</em>), glorify (<em>dote... doxan</em>), worship (<em>proskunēsate</em>). The <em>hōra</em> (hour) of judgment has arrived — the eschatological hour whose arrival was anticipated throughout John's Gospel (John 12:23: the hour has come). <em>Proskunēsate tō poiēsanti ton ouranon kai tēn gēn</em> (worship the one who made heaven and earth) — the creator-worship call directly counters the beast-worship of ch13:4.</p>",
    "8": "<p><em>Epesen, epesen Babylōn hē megalē</em> (fallen, fallen is Babylon the great) — the double aorist of Isa 21:9 LXX (<em>peptōken, peptōken Babylōn</em>), cited verbatim. The past tense for a future event is the prophetic perfect: Babylon's fall is so certain that it is announced as accomplished. <em>Hoti ek tou oinou tou thymou tēs porneias autēs pepotiken panta ta ethnē</em> (because she made all the nations drink of the wine of the wrath/fury of her sexual immorality) — the wine-metaphor anticipates the bowl-of-wrath judgments of ch16.</p>",
    "9": "<p><em>Ei tis proskunei to thērion kai tēn eikona autou</em> (if anyone worships the beast and its image) — the third angel's warning is the counterpart to the second beatitude (v13: blessed are those who die in the Lord); the alternative to faithful martyrdom is unfaithful beast-worship. The three criteria are: worship (<em>proskunei</em>), the mark (<em>charagma</em> on forehead/hand). These three acts of allegiance together constitute the damning choice.</p>",
    "10": "<p><em>Autos piei ek tou oinou tou thymou tou theou tou kekerasmenou akratou en tō potēriō tēs orgēs autou</em> (he will drink the wine of God's wrath, mixed undiluted in the cup of his fury) — the wine of divine wrath is from the OT motif of the cup of divine wrath (Jer 25:15; Ps 75:8; Isa 51:17). <em>Kekerasmenou akratou</em> (mixed undiluted) — the paradox: wine was normally diluted with water; this wine is 'mixed' (prepared) but 'undiluted' (<em>akratos</em>), i.e., full strength. <em>Basanisthēsetai en pyri kai theiō</em> (he will be tormented in fire and sulfur) — the fire-and-sulfur motif from Gen 19:24 (Sodom) and Ezek 38:22.</p>",
    "11": "<p><em>Ho kapnos tou basanismou autōn eis aiōnas aiōnōn anabainei</em> (the smoke of their torment rises forever and ever) — drawn from the smoke of Edom's destruction in Isa 34:10 (night and day it shall not be quenched; its smoke shall go up forever). <em>Kai ouk echousin anapausin hēmeras kai nyktos hoi proskunountes to thērion</em> (they have no rest, day or night, those who worship the beast) — the negative of the rest promised to those who die in the Lord (v13: <em>anapausontai</em>); beast-worshippers receive the anti-rest that contrasts with the Sabbath-rest of the redeemed.</p>",
    "12": "<p><em>Hōde hē hypomonē tōn hagiōn estin, hoi tērountes tas entolas tou theou kai tēn pistin Iēsou</em> (here is the patient endurance of the saints, those who keep the commandments of God and the faith of Jesus) — the paraenetic hinge between the warning oracle (vv. 9-11) and the beatitude (v13). <em>Hypomonē</em> (patient endurance/steadfastness) is the key virtue under persecution (cf. 13:10). <em>Tēn pistin Iēsou</em> (the faith of Jesus) — genitive ambiguity: the faithfulness that Jesus himself exemplified (subjective genitive) or faith in/about Jesus (objective genitive); John's pattern supports the subjective: the community participates in Jesus's own faithful perseverance.</p>",
    "13": "<p><em>Makarioi hoi nekroi hoi en kyriō apothnēskontes apo arti</em> (blessed are the dead who die in the Lord from now on) — the second beatitude (cf. 1:3) addressed to those martyred after John's writing (<em>apo arti</em>, from now on). <em>Hina anapausontai ek tōn kopōn autōn</em> (that they may rest from their labors) — the <em>anapausis</em> (rest) promised to those who die in the Lord contrasts with the <em>ouk echousin anapausin</em> (no rest) of the beast-worshippers (v11). <em>Ta gar erga autōn akolouthei met autōn</em> (for their works follow them) — the works of the faithful accompany them into their rest; death does not erase what was done in the Lord.</p>",
    "14": "<p><em>Eidon, kai idou nephele leukē, kai epi tēn nephelēn kathēmenon homoion huiō anthrōpou</em> (I saw, and behold, a white cloud, and seated on the cloud was one like a son of man) — the <em>homoion huiō anthrōpou</em> (one like a son of man) on a white cloud cites Dan 7:13 (one like a son of man came with the clouds of heaven). The harvest-figure has <em>stephanos chrysous</em> (a golden crown, victory wreath) and <em>drepanon oxy</em> (sharp sickle) — the eschatological reaper. The white cloud is the divine glory-cloud of the exodus (Exod 13:21) and transfiguration (Matt 17:5) adapted for the parousia scene.</p>",
    "15": "<p><em>Pempsōn to drepanon sou kai therison</em> (send your sickle and reap) — the angel from the temple instructs the one on the cloud, fulfilling Joel 3:13 LXX (<em>exaposteilate drepana hoti parestēken trygētos</em>, send out the sickles for the harvest has come). The <em>hōra</em> (hour) of reaping has come; the eschatological harvest is the gathering of the grain-field of the earth. Whether this first harvest (vv. 14-16) is a grain-harvest of the righteous (to be rescued) or a harvest of judgment is debated; the grape-harvest that follows (vv. 17-20) is clearly one of judgment.</p>",
    "16": "<p><em>Kai ebalen ho kathēmenos epi tēs nephelēs to drepanon autou epi tēs gēs kai etristhē hē gē</em> (the one seated on the cloud swung his sickle and the earth was reaped) — the single verb <em>etristhē</em> (was reaped/harvested) describes the complete harvest of the earth; the aorist passive indicates divine action executed through the Son-of-Man figure. The economy of language is deliberate: the first harvest is described in a single verse, while the grape-harvest receives four detailed verses (vv. 17-20).</p>",
    "17": "<p><em>Kai allos angelos exēlthen ek tou naou tou en tō ouranō</em> (another angel came out of the temple in heaven) — the sequence of angelic reapers: the first angel commands the Son-of-Man figure (v15), the second angel carries a sickle for the grape harvest, the third angel (v18) comes from the altar with fire authority. The temple origin (<em>ek tou naou</em>) of the angels establishes that the judgment proceeds from the divine sanctuary — it is liturgically authorized.</p>",
    "18": "<p><em>Allos angelos ek tou thysiastēriou, ho echōn exousian epi tou pyros</em> (another angel from the altar, the one having authority over the fire) — the fire-altar angel recalls 8:3-5 (the altar angel who mixed prayers with incense and hurled fire to the earth); here the same fire-authority is exercised in the grape-harvest judgment. The prayers of the saints (8:4) that rose with the incense contributed to this judgment sequence; the altar is the source of both intercession and judgment.</p>",
    "19": "<p><em>Kai ebalen ho angelos to drepanon autou eis tēn gēn kai etrygēsen tēn ampelon tēs gēs kai ebalen eis tēn lēnon tou thymou tou theou ton megan</em> (the angel swung his sickle and gathered the grape harvest and threw it into the great winepress of God's wrath) — the <em>lēnos</em> (winepress) of God's wrath is Joel 3:13 (<em>piesate hoti plērēs to lēnos</em>, press the wine for the winepress is full) combined with Isa 63:3 (I have trodden the wine press alone). The winepress of God's wrath will reappear in 19:15 as the location where the rider-on-the-white-horse treads.</p>",
    "20": "<p><em>Kai epatēthē hē lēnos exōthen tēs poleōs kai exēlthen haima ek tēs lēnou achri tōn chalinōn tōn hippōn apo stadiōn chiliōn hexakosion</em> (the winepress was trodden outside the city, and blood flowed for 1,600 stadia) — <em>exōthen tēs poleōs</em> (outside the city) alludes to the place of crucifixion (John 19:20: the place was near the city) — the blood that flows from the winepress connects to the blood of the cross; here the judgment-blood flows in the direction of the passion. 1,600 stadia (= 40 × 40 ≈ 185 miles) is symbolic: 4 × 400, or 4² × 100, representing the four corners of the earth covered to the depth of horses' bridles.</p>"
  },
  "15": {
    "1": "<p><em>Eidon allo sēmeion en tō ouranō mega kai thaumaston</em> (I saw another great and marvelous sign in heaven) — the third <em>sēmeion</em> in Revelation (cf. 12:1, 3); the <em>thaumaston</em> (marvelous/wonderful) echoes the vocabulary of theophanic praise (Ps 77:14; 86:10). <em>Hepta angelous echontas plēgas hepta tas eschatas</em> (seven angels with seven last plagues) — <em>eschatas</em> (last) marks these as the culminating plagues. <em>Hoti en autais etelestheē ho thymos tou theou</em> (because in them the wrath of God is finished) — <em>etelestheē</em> (was finished/completed) — the same verb root as <em>tetelestai</em> (it is finished) of John 19:30; the wrath is 'completed' at the bowls.</p>",
    "2": "<p><em>Eidon hōs thalassan hyalinēn memigmenēn pyri kai tous nikōntas ek tou thēriou</em> (I saw what appeared to be a sea of glass mixed with fire, and those who had conquered the beast) — the <em>thalassa hyalinē</em> (sea of glass) reappears from 4:6 (before the throne a sea of glass like crystal); here it is 'mixed with fire' — the crystal transparency now has the fire of divine judgment mixed in. The overcomers stand on it with harps (<em>kitharas tou theou</em>, harps of God), echoing the Exodus sea-crossing singers of Exod 15. <em>Tous nikōntas ek tou thēriou... hestōtas epi tēn thalassan</em> — they have overcome not <em>by</em> the beast but <em>from</em> it: out of the beast's domain they have emerged victorious.</p>",
    "3": "<p><em>ōdousin tēn ōdēn Mōyseōs tou doulou tou theou kai tēn ōdēn tou arniou</em> (they were singing the song of Moses the servant of God and the song of the Lamb) — the dual song identifies the new-exodus event: Moses sang Exod 15 at the Red Sea crossing; the Lamb's song is the new exodus song sung by those who have crossed the new sea. The song's words draw from multiple OT texts: <em>Megala kai thaumasta ta erga sou, Kyrie ho Theos ho Pantokratōr</em> (great and marvelous are your works, Lord God Almighty) from Ps 111:2; Amos 4:13.</p>",
    "4": "<p><em>Tis ou mē phobēthē... kai doxasei to onoma sou</em> (who will not fear... and glorify your name) — the rhetorical question form echoes Jer 10:7 LXX (who will not fear you, O King of the nations?) and Ps 86:9 (all the nations will come and worship before you). <em>Hoti monos hosios</em> (for you alone are holy) — <em>hosios</em> (holy/devout) is different from <em>hagios</em> (holy, the common attribute of God); <em>hosios</em> connotes the faithful covenant-partner who is wholly given to God. <em>Panta ta ethnē hēxousin kai proskunēsousin enōpion sou</em> (all the nations will come and worship before you) — Ps 86:9 fulfillment; the universal worship of God at the end is the telos toward which all the nations' history moves.</p>",
    "5": "<p><em>Ēnoigē ho naos tēs skēnēs tou martyriou en tō ouranō</em> (the temple of the tent of testimony in heaven was opened) — the <em>skēnē tou martyriou</em> (tabernacle of testimony) is the LXX term for the Mosaic tabernacle (Exod 38:21; Num 1:50 etc.); the heavenly original of which the Mosaic tabernacle was a copy (Heb 8:5). Its opening at this point signals that the final act of the divine drama is being initiated from the heavenly sanctuary itself — the source of the bowl-judgments is the holy of holies.</p>",
    "6": "<p><em>Exēlthan hoi hepta angeloi... endedymenoi linon katharon lampron</em> (the seven angels came out clothed in pure, bright linen) — the <em>linon katharon lampron</em> (clean bright linen) is the priestly garment; these judgment-angels are clothed as priests enacting a priestly liturgical act. The golden sashes (<em>zōnas chrysas peri ta stēthē</em>) around the chest recall the high priest's golden garments (Exod 28:8 LXX). The bowl-judgments are performed with priestly decorum — divine wrath is not chaotic but liturgically ordered.</p>",
    "7": "<p><em>Edōken hen ek tōn tessarōn zōōn tois hepta angelois hepta phialas chrysas gemousas tou thymou tou theou</em> (one of the four living creatures gave to the seven angels seven golden bowls full of the wrath of God) — the <em>phialē</em> (bowl) is a wide, flat libation bowl used for pouring offerings; the bowls full of divine wrath are the anti-libation — instead of worshippers pouring sweet wine/water to the deity, God pours wrath on those who refused to worship him. The bowls come from the living creature (<em>zōon</em>) — the same heavenly being that gave the first four scroll-seals (ch6); the judgment proceeds from the divine presence.</p>",
    "8": "<p><em>Egemisthē ho naos kapnou ek tēs doxēs tou theou kai ek tēs dynameōs autou</em> (the temple was filled with smoke from the glory of God and from his power) — the smoke-filling of the temple echoes Exod 40:34-35 (the cloud covered the tent and the glory of the LORD filled the tabernacle) and Isa 6:4 (the house was filled with smoke) and 1 Kgs 8:10-11 (the priests could not stand to minister because the glory of the LORD filled the temple). <em>Oudeis edynato eiselthein eis ton naon achri telesōsin hai hepta plēgai tōn hepta angelōn</em> (no one could enter the temple until the seven plagues were completed) — the divine lockout of the sanctuary during the bowl-outpouring signals the irreversibility of the judgment in progress.</p>"
  },
  "16": {
    "1": "<p><em>Kai ēkousa megalēs phōnēs ek tou naou legousēs tois hepta angelois</em> (I heard a loud voice from the temple saying to the seven angels) — the command voice comes from the closed temple of 15:8; no one can enter until the judgments are complete, but the voice still issues commands from within. <em>Hypagete kai ekcheete tas hepta phialas tou thymou tou theou eis tēn gēn</em> (go and pour out the seven bowls of God's wrath on the earth) — <em>ekcheō</em> (pour out) is used of the Spirit's outpouring in Joel 2:28-29; Acts 2:17-18; here its inverse: the same verb for the Spirit poured in salvation becomes the verb for wrath poured in judgment.</p>",
    "2": "<p><em>Apēlthen ho prōtos kai execheen tēn phialēn autou eis tēn gēn</em> (the first angel went and poured out his bowl on the earth) — the first bowl-plague produces <em>helkos kakon kai ponēron</em> (a harmful and painful sore) on beast-mark bearers; the LXX <em>helkos</em> (sore/boil) is the same word used for the sixth Egyptian plague of boils (Exod 9:10-11 LXX). The specificity of the target (<em>epi tous echontas to charagma tou thēriou</em>, on those having the mark of the beast) distinguishes the bowl-plagues from the trumpet-plagues, which struck all without distinction; the bowls are targeted judgments.</p>",
    "3": "<p><em>Kai ho deuteros execheen tēn phialēn autou eis tēn thalassan</em> (the second angel poured out his bowl on the sea) — the sea becomes <em>haima hōs nekrou</em> (blood like that of a dead man) — thicker, darker, more putrid than fresh blood; the first plague (Exod 7:20-21 LXX) turned the Nile to blood; the second bowl-plague extends this to the entire sea. <em>Kai pasa psychē zōēs apethanen ta en tē thalassē</em> (every living soul died in the sea) — the total mortality contrasts with the trumpet-plagues' one-third partial judgment; the bowls complete what the trumpets began.</p>",
    "4": "<p><em>Kai ho tritos execheen tēn phialēn autou eis tous potamous kai tas pēgas tōn hydatōn, kai egeneto haima</em> (the third angel poured out his bowl on the rivers and springs, and they became blood) — the fresh-water judgment completes the water-judgment sequence: sea (v3), rivers and springs (v4). The rivers and springs are the <em>pēgai</em> (sources/springs) of fresh water — the same word used in 7:17 and 21:6 for the springs of living water that the Lamb leads the redeemed to.</p>",
    "5": "<p><em>Dikaios ei, ho ōn kai ho ēn, ho hosios, hoti tauta ekrinas</em> (you are just, O Lord, who is and who was, the Holy One, for you have judged thus) — the angel of the waters (<em>ho angelos tōn hydatōn</em>) speaks a doxological vindication of the judgment. The divine name formula <em>ho ōn kai ho ēn</em> (who is and who was) appears without the future component (<em>kai ho erchomenos</em>, and who is to come) — the coming is now being enacted in the judgments themselves. <em>Hosios</em> (holy/righteous) is predicated of God as in 15:4.</p>",
    "6": "<p><em>Hoti haima hagiōn kai prophētōn exechean kai haima autois dedōkas pein</em> (because they poured out the blood of saints and prophets, and you have given them blood to drink) — the lex talionis of divine justice: those who shed the blood of saints receive blood to drink. <em>Axioi eisin</em> (they deserve it) — the liturgical verdict that the blood-drink is fitting punishment. The logic recalls Isa 49:26 (I will make your oppressors eat their own flesh) and the reversal of Ps 79:3 (they shed blood like water).</p>",
    "7": "<p><em>Kai ēkousa tou thysiastēriou legontos, Nai, Kyrie ho Theos ho Pantokratōr, alēthinai kai dikaiai hai kriseis sou</em> (and I heard the altar saying, 'Yes, Lord God Almighty, true and just are your judgments') — the altar speaks; the same altar under which the martyrs' souls cried for vindication (6:9-10) now affirms the justice of the bowl-judgments as their vindication. <em>Pantokratōr</em> (Almighty) is the dominant divine title in Revelation (1:8; 4:8; 11:17; 15:3; 16:7, 14; 19:6, 15; 21:22), emphasizing God's absolute sovereignty over all the beast's apparent power.</p>",
    "8": "<p><em>Kai ho tetartos execheen tēn phialēn autou epi ton hēlion</em> (the fourth angel poured out his bowl on the sun) — the fourth bowl-plague reverses the fourth trumpet: the trumpet darkened the sun (8:12), the bowl intensifies it. <em>Edothē autō kaumatisai tous anthrōpous en pyri</em> (it was given to it to scorch people with fire) — the passive <em>edothē</em> governs the sun's intensified scorching; even the sun operates within divine permission. The scorching by fire anticipates the lake of fire judgment (20:10-15).</p>",
    "9": "<p><em>Kai ekaumatisthēsan hoi anthrōpoi kauma mega kai eblasphēmēsan to onoma tou theou</em> (people were scorched by the intense heat and blasphemed the name of God) — the hardening-response to judgment: instead of repentance (<em>ou metanoēsan dounai autō doxan</em>, they did not repent and give him glory), the afflicted blaspheme. The refusal of repentance is itself judgment: the heart that hardens under judgment is already in a state of anti-worship, and the judgment confirms it. The pattern echoes Pharaoh's hardening under the plagues (Exod 7:22; 8:15 etc.).</p>",
    "10": "<p><em>Kai ho pemptos execheen tēn phialēn autou epi ton thronon tou thēriou</em> (the fifth angel poured out his bowl on the throne of the beast) — the fifth bowl targets the beast's own seat of authority (<em>thronos</em>), plunging his kingdom into darkness. <em>Egeneto hē basileia autou eskotōmenē</em> (his kingdom was plunged into darkness) — the darkness-plague echoes the ninth Egyptian plague (Exod 10:21-23 LXX); here it is eschatologically intensified and directed specifically at the anti-God empire. The beast's darkness contrasts with the city that needs no sun or moon (21:23).</p>",
    "11": "<p><em>Kai eblasphēmēsan ton theon tou ouranou ek tōn ponōn autōn kai ek tōn helkōn autōn</em> (they blasphemed the God of heaven because of their pains and their sores) — <em>ouk metenoesan ek tōn ergōn autōn</em> (they did not repent of their works) — the double refusal of repentance (cf. v9) after both the scorching and the darkness solidifies the pattern: the bowl-judgments do not produce repentance but confirm established orientations. The sores from the first bowl (v2) still torment them — the plagues accumulate rather than conclude between bowls.</p>",
    "12": "<p><em>Kai ho hektos execheen tēn phialēn autou epi ton potamon ton megan ton Euphratēn</em> (the sixth angel poured out his bowl on the great river Euphrates) — the Euphrates was the eastern boundary of the Promised Land (Gen 15:18) and the direction from which Babylon's armies came against Israel (Jer 46:10; Isa 8:7). <em>Kai exēranthē to hydōr autou</em> (its water was dried up) — the drying of the Euphrates echoes Isa 11:15 (the LORD will dry up the tongue of the Egyptian sea and wave his hand over the Euphrates and split it into seven streams) and Jer 50:38 (a drought against her waters). <em>Hina hetoimasthē hē hodos tōn basileōn tōn apo anatolēs hēliou</em> (to prepare the way for the kings from the east) — clearing the path for a final assault on Babylon.</p>",
    "13": "<p><em>Eidon ek tou stomatos tou drakontos kai ek tou stomatos tou thēriou kai ek tou stomatos tou pseudoprophētou pneumata tria akatharta hōs batrachoi</em> (I saw from the mouth of the dragon, from the mouth of the beast, and from the mouth of the false prophet, three impure spirits like frogs) — the infernal trinity speaks through the frog-spirits; the frog imagery echoes the second Egyptian plague (Exod 8:1-15 LXX). The three mouths of the three members of the infernal trinity emit three spirits — a deceptive missionary force that mirrors the three spirits of truth.</p>",
    "14": "<p><em>Eisin gar pneumata daimoniōn poiounta sēmeia</em> (for they are demonic spirits performing signs) — the demonic spirits' <em>sēmeia</em> (signs) are the counterfeit of the signs that authenticated the apostolic gospel (Heb 2:4; Acts 2:22); their purpose is to gather the kings to battle. <em>Epi ton polemon tēs hēmeras tēs megalēs tou theou tou Pantokratoros</em> (for the battle of the great day of God the Almighty) — the gathering to battle is ultimately God's gathering, not the dragon's; the eschatological assembly is providentially directed (cf. Ezek 38-39: Gog gathered from all directions for the final battle).</p>",
    "15": "<p><em>Idou erchomai hōs kleptēs</em> (Look, I come like a thief) — the parenthetical warning voice of Christ (cf. 3:3; Matt 24:43-44; 1 Thess 5:2, 4; 2 Pet 3:10) interrupts the battle-gathering narrative. <em>Makarios ho grēgorōn kai tērōn ta himatia autou</em> (blessed is the one who stays awake and keeps his garments) — the fifth beatitude of Revelation (1:3; 14:13; 16:15; 19:9; 20:6; 22:7, 14); the garments-keeping recalls the Sardis letter (3:4-5: those who have not soiled their garments) and the white garments of the overcomer.</p>",
    "16": "<p><em>Kai synēgagen autous eis ton topon ton kaloumenon Hebraisti Armagedōn</em> (they gathered them to the place called in Hebrew Armageddon) — <em>Harmagedōn</em> (Armageddon) = Hebrew <em>har megiddo</em> (mountain/hill of Megiddo). Megiddo was the great battlefield of Israel's history: Deborah and Barak defeated Sisera there (Judg 5:19), Josiah was killed there (2 Kgs 23:29; 2 Chr 35:22). Zechariah's mourning at Megiddo (Zech 12:11) provides the eschatological reference. The 'mountain' (<em>har</em>) of Megiddo is symbolic rather than geographical — Megiddo is in a plain.</p>",
    "17": "<p><em>Kai ho hebdomos execheen tēn phialēn autou epi ton aera</em> (the seventh angel poured out his bowl into the air) — the air (<em>aēr</em>) is the realm of the prince of the power of the air (Eph 2:2; Satan's domain); the seventh bowl strikes his territory directly. <em>Kai exēlthen phōnē megalē apo tou naou apo tou thronou legousa, Gegonen</em> (a great voice came from the temple, from the throne, saying, 'It is done') — <em>Gegonen</em> (it is done/it has happened) is the perfect tense of <em>ginomai</em> (to become/happen); cf. 21:6 (the same word spoken at the new creation's completion); both the completion of judgment and the completion of new creation use the same word.</p>",
    "18": "<p><em>Kai egenonto astrapai kai phōnai kai brontai kai seismos egeneto megas</em> (there came flashes of lightning, rumblings, peals of thunder, and a great earthquake) — the theophanic storm-quartet appears at each culminating moment in Revelation: at the opening of the seventh seal (8:5), the sounding of the seventh trumpet (11:19), and now the seventh bowl. <em>Hoios ouk egeneto aph hou anthrōpoi egenonto epi tēs gēs tēlikos seismos houtōs megas</em> (a severe earthquake unlike anything since humanity was on the earth) — the superlative earthquake language draws on Dan 12:1 (a time of trouble such as has not been since there was a nation) and Ezek 38:19-20.</p>",
    "19": "<p><em>Kai egeneto hē polis hē megalē eis tria merē</em> (the great city split into three parts) — the 'great city' (<em>polis hē megalē</em>) is John's consistent designation for Babylon/Rome (11:8; 14:8; 16:19; 17:18; 18:2, 10, 16, 18-19, 21). <em>Kai Babylōn hē megalē emnesthē enōpion tou theou dounai autē to potērion tou oinou tou thymou tēs orgēs autou</em> (and God remembered Babylon the great and gave her the cup of the wine of his furious wrath) — the divine <em>emnesthē</em> (remembered) is the covenant word: as God remembered Noah (Gen 8:1) and Israel in Egypt (Exod 2:24) for deliverance, he here remembers Babylon for judgment. The cup of wrath (Jer 25:15; Ps 75:8) is now poured.</p>",
    "20": "<p><em>Kai pasa nēsos ephygen kai orē ouch heurethēsan</em> (every island fled away and the mountains could no longer be found) — the de-creation of the geographical order: islands and mountains, the stable features of the ancient world (Ps 46:2: though the mountains be moved into the heart of the sea), flee at the seventh bowl. The language echoes 6:14 (every mountain and island was moved from its place) but now is total; no stable geography remains for the beast's political order to occupy.</p>",
    "21": "<p><em>Kai chalaza megalē hōs talantiaiaai katabainei ek tou ouranou epi tous anthrōpous</em> (huge hailstones, each weighing about a talent, fell from heaven on people) — the hail of 29 kg (~64 lb) stones inverts the first trumpet's hail (8:7) by an order of magnitude. The hail echoes the seventh Egyptian plague (Exod 9:18-26 LXX) and Josh 10:11 (the LORD threw great hailstones from heaven on them). <em>Kai eblasphēmēsan hoi anthrōpoi ton theon ek tēs plēgēs tēs chalazes</em> (people blasphemed God because of the plague of hail) — the final verdict on the hardened: even the eschatological hail-judgment produces not repentance but only intensified blasphemy. The judgment confirms rather than converts.</p>"
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-original', 'revelation')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-original', 'revelation', existing)
    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'revelation.json'))
    all_ok = True
    for ch in range(12, 17):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(existing.get(ck, {}).keys())
        if missing:
            print(f'  ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch {ch}: complete ({len(existing.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')
